import type { AgentEvent } from "@mariozechner/pi-agent-core";

// ── Transcript types ──

export type TranscriptEntry =
	| { kind: "text"; text: string; timestamp: number }
	| { kind: "tool_start"; toolName: string; timestamp: number }
	| { kind: "tool_end"; toolName: string; durationMs: number; timestamp: number }
	| { kind: "turn_end"; turnNumber: number; tokens: number; timestamp: number };

const MAX_TRANSCRIPT = 200;

export class TranscriptLog {
	private entries: TranscriptEntry[] = [];

	push(entry: TranscriptEntry): void {
		this.entries.push(entry);
		if (this.entries.length > MAX_TRANSCRIPT) {
			this.entries.splice(0, this.entries.length - MAX_TRANSCRIPT);
		}
	}

	getEntries(): readonly TranscriptEntry[] {
		return this.entries;
	}

	get length(): number {
		return this.entries.length;
	}

	reset(): void {
		this.entries = [];
	}
}

export class TranscriptTracker {
	private logs = new Map<string, TranscriptLog>();
	private toolStarts = new Map<string, Map<string, number>>(); // name -> toolCallId -> startTimestamp
	private pendingText = new Map<string, string>(); // name -> accumulated text
	private turnCounts = new Map<string, number>();
	private lastTokens = new Map<string, number>(); // name -> tokens from last message_end

	handleEvent(name: string, ev: AgentEvent): void {
		const log = this.getOrCreate(name);
		const now = Date.now();

		if (ev.type === "message_update") {
			const ame = ev.assistantMessageEvent;
			if (ame.type === "text_delta") {
				const cur = this.pendingText.get(name) ?? "";
				this.pendingText.set(name, cur + ame.delta);
				// Flush complete lines
				this.flushText(name, log, now, false);
			}
			return;
		}

		if (ev.type === "tool_execution_start") {
			// Flush any pending text before a tool starts
			this.flushText(name, log, now, true);
			const starts = this.toolStarts.get(name) ?? new Map<string, number>();
			starts.set(ev.toolCallId, now);
			this.toolStarts.set(name, starts);
			log.push({ kind: "tool_start", toolName: ev.toolName, timestamp: now });
			return;
		}

		if (ev.type === "tool_execution_end") {
			const starts = this.toolStarts.get(name);
			const startTs = starts?.get(ev.toolCallId);
			const durationMs = startTs === undefined ? 0 : now - startTs;
			starts?.delete(ev.toolCallId);
			log.push({ kind: "tool_end", toolName: ev.toolName, durationMs, timestamp: now });
			return;
		}

		if (ev.type === "message_end") {
			// Capture tokens for use in the turn_end entry
			const msg: unknown = ev.message;
			if (isRecord(msg)) {
				const usage = msg.usage;
				if (isRecord(usage) && typeof usage.totalTokens === "number") {
					this.lastTokens.set(name, (this.lastTokens.get(name) ?? 0) + usage.totalTokens);
				}
			}
			return;
		}

		if (ev.type === "agent_end") {
			// Flush remaining text
			this.flushText(name, log, now, true);
			const turn = (this.turnCounts.get(name) ?? 0) + 1;
			this.turnCounts.set(name, turn);
			const tokens = this.lastTokens.get(name) ?? 0;
			log.push({ kind: "turn_end", turnNumber: turn, tokens, timestamp: now });
			this.lastTokens.set(name, 0);
			return;
		}
	}

	get(name: string): TranscriptLog {
		return this.logs.get(name) ?? new TranscriptLog();
	}

	reset(name: string): void {
		this.logs.delete(name);
		this.toolStarts.delete(name);
		this.pendingText.delete(name);
		this.turnCounts.delete(name);
		this.lastTokens.delete(name);
	}

	private getOrCreate(name: string): TranscriptLog {
		const existing = this.logs.get(name);
		if (existing) return existing;
		const created = new TranscriptLog();
		this.logs.set(name, created);
		return created;
	}

	private flushText(name: string, log: TranscriptLog, timestamp: number, force: boolean): void {
		const buf = this.pendingText.get(name);
		if (!buf) return;

		// Split into lines; keep the last incomplete line unless forced
		const parts = buf.split("\n");
		if (force) {
			// Flush everything
			for (const part of parts) {
				const trimmed = part.trimEnd();
				if (trimmed) log.push({ kind: "text", text: trimmed, timestamp });
			}
			this.pendingText.delete(name);
		} else if (parts.length > 1) {
			// Flush all complete lines, keep the last (potentially incomplete) part
			for (let i = 0; i < parts.length - 1; i++) {
				const part = parts[i];
				if (part === undefined) continue;
				const trimmed = part.trimEnd();
				if (trimmed) log.push({ kind: "text", text: trimmed, timestamp });
			}
			this.pendingText.set(name, parts[parts.length - 1] ?? "");
		}
	}
}

// ── Activity types ──

type TrackedEventType = "tool_execution_start" | "tool_execution_end" | "agent_end" | "message_end";

function isRecord(v: unknown): v is Record<string, unknown> {
	return typeof v === "object" && v !== null;
}

export interface TeammateActivity {
	toolUseCount: number;
	currentToolName: string | null;
	lastToolName: string | null;
	turnCount: number;
	totalTokens: number;
	recentEvents: Array<{ type: TrackedEventType; toolName?: string; timestamp: number }>;
}

const MAX_RECENT = 10;

function emptyActivity(): TeammateActivity {
	return {
		toolUseCount: 0,
		currentToolName: null,
		lastToolName: null,
		turnCount: 0,
		totalTokens: 0,
		recentEvents: [],
	};
}

export class ActivityTracker {
	private data = new Map<string, TeammateActivity>();

	handleEvent(name: string, ev: AgentEvent): void {
		const a = this.getOrCreate(name);
		const now = Date.now();

		if (ev.type === "tool_execution_start") {
			a.currentToolName = ev.toolName;
			a.recentEvents.push({ type: ev.type, toolName: ev.toolName, timestamp: now });
			if (a.recentEvents.length > MAX_RECENT) a.recentEvents.shift();
			return;
		}

		if (ev.type === "tool_execution_end") {
			const toolName = a.currentToolName ?? ev.toolName;
			a.toolUseCount++;
			a.lastToolName = toolName;
			a.currentToolName = null;
			a.recentEvents.push({ type: ev.type, toolName, timestamp: now });
			if (a.recentEvents.length > MAX_RECENT) a.recentEvents.shift();
			return;
		}

		if (ev.type === "agent_end") {
			a.turnCount++;
			a.recentEvents.push({ type: ev.type, timestamp: now });
			if (a.recentEvents.length > MAX_RECENT) a.recentEvents.shift();
			return;
		}

		if (ev.type === "message_end") {
			const msg: unknown = ev.message;
			if (!isRecord(msg)) return;
			const usage = msg.usage;
			if (!isRecord(usage)) return;
			const totalTokens = usage.totalTokens;
			if (typeof totalTokens === "number") a.totalTokens += totalTokens;
		}
	}

	get(name: string): TeammateActivity {
		return this.data.get(name) ?? emptyActivity();
	}

	reset(name: string): void {
		this.data.delete(name);
	}

	private getOrCreate(name: string): TeammateActivity {
		const existing = this.data.get(name);
		if (existing) return existing;

		const created = emptyActivity();
		this.data.set(name, created);
		return created;
	}
}

import { spawn } from "node:child_process";
import type { AgentEvent } from "@mariozechner/pi-agent-core";

export type TeammateStatus = "starting" | "idle" | "streaming" | "stopped" | "error";

type RpcCommand =
	| { id: string; type: "prompt"; message: string }
	| { id: string; type: "steer"; message: string }
	| { id: string; type: "follow_up"; message: string }
	| { id: string; type: "abort" }
	| { id: string; type: "get_state" }
	| { id: string; type: "set_session_name"; name: string };

type DistributiveOmit<T, K extends PropertyKey> = T extends unknown ? Omit<T, K> : never;

type RpcCommandWithoutId = DistributiveOmit<RpcCommand, "id">;

type RpcResponse = {
	id?: string;
	type: "response";
	command: string;
	success: boolean;
	data?: unknown;
	error?: string;
};

function isRecord(v: unknown): v is Record<string, unknown> {
	return typeof v === "object" && v !== null;
}

function safeParseJsonLine(line: string): unknown | null {
	try {
		return JSON.parse(line);
	} catch {
		return null;
	}
}

function isRpcResponse(v: unknown): v is RpcResponse {
	if (!isRecord(v)) return false;
	if (v.type !== "response") return false;
	if (typeof v.command !== "string") return false;
	if (typeof v.success !== "boolean") return false;
	if (v.id !== undefined && typeof v.id !== "string") return false;
	if (v.error !== undefined && typeof v.error !== "string") return false;
	return true;
}

function isAgentEvent(v: unknown): v is AgentEvent {
	if (!isRecord(v)) return false;
	if (typeof v.type !== "string") return false;

	// Validate the minimal shapes we actually dereference below.
	if (v.type === "message_update") {
		const ame = v.assistantMessageEvent;
		if (!isRecord(ame)) return false;
		if (typeof ame.type !== "string") return false;
		if (ame.type === "text_delta" && typeof ame.delta !== "string") return false;
		return true;
	}

	if (v.type === "tool_execution_start" || v.type === "tool_execution_update" || v.type === "tool_execution_end") {
		if (typeof v.toolCallId !== "string") return false;
		if (typeof v.toolName !== "string") return false;
		return true;
	}

	return (
		v.type === "agent_start" ||
		v.type === "agent_end" ||
		v.type === "turn_start" ||
		v.type === "turn_end" ||
		v.type === "message_start" ||
		v.type === "message_end"
	);
}

export class TeammateRpc {
	readonly name: string;
	readonly sessionFile?: string;

	status: TeammateStatus = "starting";
	lastAssistantText = "";
	lastError: string | null = null;

	/** Task currently assigned by the team lead (if any). */
	currentTaskId: string | null = null;

	private proc: ReturnType<typeof spawn> | null = null;
	private pending = new Map<string, { resolve: (v: RpcResponse) => void; reject: (e: Error) => void }>();
	private nextId = 0;
	private buffer = "";
	private stderr = "";
	private eventListeners: Array<(ev: AgentEvent) => void> = [];
	private closeListeners: Array<(code: number | null) => void> = [];

	constructor(name: string, sessionFile?: string) {
		this.name = name;
		this.sessionFile = sessionFile;
	}

	onEvent(listener: (ev: AgentEvent) => void): () => void {
		this.eventListeners.push(listener);
		return () => {
			const idx = this.eventListeners.indexOf(listener);
			if (idx >= 0) this.eventListeners.splice(idx, 1);
		};
	}

	onClose(listener: (code: number | null) => void): () => void {
		this.closeListeners.push(listener);
		return () => {
			const idx = this.closeListeners.indexOf(listener);
			if (idx >= 0) this.closeListeners.splice(idx, 1);
		};
	}

	getStderr(): string {
		return this.stderr;
	}

	async start(opts: { cwd: string; env: Record<string, string>; args: string[] }): Promise<void> {
		if (this.proc) throw new Error("Teammate already started");

		this.proc = spawn("pi", ["--mode", "rpc", ...opts.args], {
			cwd: opts.cwd,
			env: { ...process.env, ...opts.env },
			stdio: ["pipe", "pipe", "pipe"],
		});

		this.proc.on("error", (err) => {
			this.status = "error";
			this.lastError = String(err);
			for (const [id, p] of this.pending.entries()) {
				p.reject(new Error(`Process error before response (id=${id}): ${String(err)}`));
			}
			this.pending.clear();
		});

		this.proc.stderr?.on("data", (d) => {
			this.stderr += d.toString();
		});

		this.proc.stdout?.on("data", (d) => {
			this.buffer += d.toString();
			let idx: number;
			while ((idx = this.buffer.indexOf("\n")) >= 0) {
				const line = this.buffer.slice(0, idx);
				this.buffer = this.buffer.slice(idx + 1);
				this.handleLine(line);
			}
		});

		this.proc.on("close", (code) => {
			this.status = code === 0 ? "stopped" : "error";
			if (code !== 0) this.lastError = `Teammate process exited with code ${code}`;
			for (const [id, p] of this.pending.entries()) {
				p.reject(new Error(`Process exited before response (id=${id})`));
			}
			this.pending.clear();
			for (const l of this.closeListeners) l(code);
		});

		// Give the child a moment to boot.
		await new Promise((r) => setTimeout(r, 120));
		this.status = "idle";
	}

	async stop(): Promise<void> {
		if (!this.proc) return;
		try {
			await this.abort();
		} catch {
			// ignore
		}
		this.proc.kill("SIGTERM");
		setTimeout(() => {
			if (this.proc && !this.proc.killed) this.proc.kill("SIGKILL");
		}, 1000);
		this.proc = null;
		this.status = "stopped";
	}

	async prompt(message: string): Promise<void> {
		await this.send({ type: "prompt", message });
	}

	async steer(message: string): Promise<void> {
		await this.send({ type: "steer", message });
	}

	async followUp(message: string): Promise<void> {
		await this.send({ type: "follow_up", message });
	}

	async abort(): Promise<void> {
		await this.send({ type: "abort" });
	}

	async getState(): Promise<unknown> {
		const resp = await this.send({ type: "get_state" });
		return resp.data;
	}

	async setSessionName(name: string): Promise<void> {
		await this.send({ type: "set_session_name", name });
	}

	private handleLine(line: string) {
		if (!line.trim()) return;
		const obj = safeParseJsonLine(line);
		if (obj === null) return;

		// Response
		if (isRpcResponse(obj)) {
			if (typeof obj.id !== "string") return;
			const pending = this.pending.get(obj.id);
			if (!pending) return;
			this.pending.delete(obj.id);
			pending.resolve(obj);
			return;
		}

		// Agent event
		if (!isAgentEvent(obj)) return;
		const ev = obj;
		if (ev.type === "agent_start") {
			this.status = "streaming";
			this.lastAssistantText = "";
		}
		if (ev.type === "agent_end") {
			this.status = "idle";
		}
		if (ev.type === "message_update") {
			const ame = ev.assistantMessageEvent;
			if (ame.type === "text_delta") {
				this.lastAssistantText += ame.delta;
			}
		}

		for (const l of this.eventListeners) l(ev);
	}

	private async send(cmd: RpcCommandWithoutId): Promise<RpcResponse> {
		if (!this.proc || !this.proc.stdin) throw new Error("Teammate is not running");
		const id = `req-${this.name}-${this.nextId++}`;
		const full = { id, ...cmd } satisfies RpcCommand;

		const payload = JSON.stringify(full) + "\n";
		this.proc.stdin.write(payload);

		return await new Promise<RpcResponse>((resolve, reject) => {
			this.pending.set(id, { resolve, reject });
			setTimeout(() => {
				if (!this.pending.has(id)) return;
				this.pending.delete(id);
				reject(new Error(`Timeout waiting for response (id=${id}, cmd=${full.type})`));
			}, 60_000);
		});
	}
}

import type { ExtensionCommandContext } from "@mariozechner/pi-coding-agent";
import { sanitizeName } from "./names.js";
import { getTeamDir, getTeamsRootDir } from "./paths.js";
import type { TeammateRpc } from "./teammate-rpc.js";
import type { TeamConfig, TeamMember } from "./team-config.js";
import type { TeamsStyle } from "./teams-style.js";
import { formatMemberDisplayName, getTeamsStrings } from "./teams-style.js";

export async function handleTeamListCommand(opts: {
	ctx: ExtensionCommandContext;
	teammates: Map<string, TeammateRpc>;
	getTeamConfig: () => TeamConfig | null;
	style: TeamsStyle;
	refreshTasks: () => Promise<void>;
	renderWidget: () => void;
}): Promise<void> {
	const { ctx, teammates, getTeamConfig, style, refreshTasks, renderWidget } = opts;
	const strings = getTeamsStrings(style);

	await refreshTasks();

	const teamConfig = getTeamConfig();
	const cfgWorkers = (teamConfig?.members ?? []).filter((m) => m.role === "worker");
	const cfgByName = new Map<string, TeamMember>();
	for (const m of cfgWorkers) cfgByName.set(m.name, m);

	const names = new Set<string>();
	for (const name of teammates.keys()) names.add(name);
	for (const name of cfgByName.keys()) names.add(name);

	if (names.size === 0) {
		ctx.ui.notify(`No ${strings.memberTitle.toLowerCase()}s`, "info");
		renderWidget();
		return;
	}

	const lines: string[] = [];
	for (const name of Array.from(names).sort()) {
		const rpc = teammates.get(name);
		const cfg = cfgByName.get(name);
		const status = rpc ? rpc.status : cfg?.status ?? "offline";
		const kind = rpc ? "rpc" : cfg ? "manual" : "unknown";
		lines.push(`${formatMemberDisplayName(style, name)}: ${status} (${kind})`);
	}

	ctx.ui.notify(lines.join("\n"), "info");
	renderWidget();
}

export async function handleTeamIdCommand(opts: {
	ctx: ExtensionCommandContext;
	teamId: string;
	taskListId: string | null;
	leadName: string;
	style: TeamsStyle;
}): Promise<void> {
	const { ctx, teamId, taskListId, leadName, style } = opts;
	const sessionTeamId = ctx.sessionManager.getSessionId();
	const effectiveTlId = taskListId ?? teamId;
	const teamsRoot = getTeamsRootDir();
	const teamDir = getTeamDir(teamId);

	ctx.ui.notify(
		[
			`teamId: ${teamId}`,
			...(teamId !== sessionTeamId ? [`sessionTeamId: ${sessionTeamId}`] : []),
			`taskListId: ${effectiveTlId}`,
			`leadName: ${leadName}`,
			`style: ${style}`,
			`teamsRoot: ${teamsRoot}`,
			`teamDir: ${teamDir}`,
		].join("\n"),
		"info",
	);
}

export async function handleTeamEnvCommand(opts: {
	ctx: ExtensionCommandContext;
	rest: string[];
	teamId: string;
	taskListId: string | null;
	leadName: string;
	style: TeamsStyle;
	getTeamsExtensionEntryPath: () => string | null;
	shellQuote: (v: string) => string;
}): Promise<void> {
	const { ctx, rest, teamId, taskListId, leadName, style, getTeamsExtensionEntryPath, shellQuote } = opts;

	const nameRaw = rest[0];
	if (!nameRaw) {
		ctx.ui.notify("Usage: /team env <name>", "error");
		return;
	}

	const name = sanitizeName(nameRaw);
	const effectiveTlId = taskListId ?? teamId;
	const teamsRoot = getTeamsRootDir();
	const teamDir = getTeamDir(teamId);
	const autoClaim = (process.env.PI_TEAMS_DEFAULT_AUTO_CLAIM ?? "1") === "1" ? "1" : "0";

	const teamsEntry = getTeamsExtensionEntryPath();
	const piCmd = teamsEntry ? `pi --no-extensions -e ${shellQuote(teamsEntry)}` : "pi";

	const env: Record<string, string> = {
		PI_TEAMS_ROOT_DIR: teamsRoot,
		PI_TEAMS_WORKER: "1",
		PI_TEAMS_TEAM_ID: teamId,
		PI_TEAMS_TASK_LIST_ID: effectiveTlId,
		PI_TEAMS_AGENT_NAME: name,
		PI_TEAMS_LEAD_NAME: leadName,
		PI_TEAMS_STYLE: style,
		PI_TEAMS_AUTO_CLAIM: autoClaim,
	};

	const exportLines = Object.entries(env)
		.map(([k, v]) => `export ${k}=${shellQuote(v)}`)
		.join("\n");

	const oneLiner = Object.entries(env)
		.map(([k, v]) => `${k}=${shellQuote(v)}`)
		.join(" ")
		.concat(` ${piCmd}`);

	ctx.ui.notify(
		[
			`teamId: ${teamId}`,
			`taskListId: ${effectiveTlId}`,
			`leadName: ${leadName}`,
			`teamsRoot: ${teamsRoot}`,
			`teamDir: ${teamDir}`,
			"",
			"Env (copy/paste):",
			exportLines,
			"",
			"Run:",
			oneLiner,
		].join("\n"),
		"info",
	);
}

const SONNET4_DEPRECATED_MARKER = "claude-sonnet-4";
const SONNET45_ALLOWED_MARKERS = ["claude-sonnet-4-5", "claude-sonnet-4.5"];

function normalizeModelId(modelId: string): string {
	return modelId.trim().toLowerCase();
}

function hasAnyMarker(value: string, markers: readonly string[]): boolean {
	for (const marker of markers) {
		if (value.includes(marker)) return true;
	}
	return false;
}

function trimOrUndefined(value: string | undefined): string | undefined {
	if (value === undefined) return undefined;
	const trimmed = value.trim();
	return trimmed.length > 0 ? trimmed : undefined;
}

export function isDeprecatedTeammateModelId(modelId: string): boolean {
	const normalized = normalizeModelId(modelId);
	if (!normalized) return false;
	if (!normalized.includes(SONNET4_DEPRECATED_MARKER)) return false;
	if (hasAnyMarker(normalized, SONNET45_ALLOWED_MARKERS)) return false;

	const idx = normalized.indexOf(SONNET4_DEPRECATED_MARKER);
	const next = normalized.at(idx + SONNET4_DEPRECATED_MARKER.length);
	if (!next) return true;
	return next === "-" || next === "_" || next === "." || next === ":";
}

export type TeammateModelSource = "override" | "inherit_leader" | "default";

export interface ResolvedTeammateModel {
	source: TeammateModelSource;
	provider?: string;
	modelId?: string;
	warnings: string[];
}

export type ResolveTeammateModelResult =
	| {
			ok: true;
			value: ResolvedTeammateModel;
	  }
	| {
			ok: false;
			error: string;
			reason: "invalid_override" | "deprecated_override";
	  };

export function formatProviderModel(provider: string | undefined, modelId: string | undefined): string | null {
	if (!modelId) return null;
	return provider ? `${provider}/${modelId}` : modelId;
}

export function resolveTeammateModelSelection(input: {
	modelOverride?: string;
	leaderProvider?: string;
	leaderModelId?: string;
}): ResolveTeammateModelResult {
	const override = trimOrUndefined(input.modelOverride);
	if (override) {
		const slashIdx = override.indexOf("/");
		if (slashIdx >= 0) {
			const provider = override.slice(0, slashIdx).trim();
			const id = override.slice(slashIdx + 1).trim();
			if (!provider || !id) {
				return {
					ok: false,
					reason: "invalid_override",
					error: `Invalid model override '${override}'. Expected <provider>/<modelId>.`,
				};
			}
			if (isDeprecatedTeammateModelId(id)) {
				return {
					ok: false,
					reason: "deprecated_override",
					error: `Model override '${override}' is deprecated. Choose a current model id.`,
				};
			}
			return {
				ok: true,
				value: {
					source: "override",
					provider,
					modelId: id,
					warnings: [],
				},
			};
		}

		if (isDeprecatedTeammateModelId(override)) {
			return {
				ok: false,
				reason: "deprecated_override",
				error: `Model override '${override}' is deprecated. Choose a current model id.`,
			};
		}

		const leaderProvider = trimOrUndefined(input.leaderProvider);
		const warnings: string[] = [];
		if (!leaderProvider) {
			warnings.push(
				`Model override '${override}' provided without a provider. ` +
					`Teammate will use its default provider; use <provider>/<modelId> to force one.`,
			);
		}
		return {
			ok: true,
			value: {
				source: "override",
				provider: leaderProvider,
				modelId: override,
				warnings,
			},
		};
	}

	const leaderModelId = trimOrUndefined(input.leaderModelId);
	const leaderProvider = trimOrUndefined(input.leaderProvider);
	if (leaderModelId && !isDeprecatedTeammateModelId(leaderModelId)) {
		return {
			ok: true,
			value: {
				source: "inherit_leader",
				provider: leaderProvider,
				modelId: leaderModelId,
				warnings: [],
			},
		};
	}

	return {
		ok: true,
		value: {
			source: "default",
			warnings: [],
		},
	};
}

