			await handleTeamPlanCommand({
				ctx,
				rest,
				teamId: activeTeamId,
				leadName,
				style,
				pendingPlanApprovals,
			});
		},
	};

	const normalizedSub = sub === "widget" ? "panel" : sub === "join" ? "attach" : sub;
	const handler = handlers[normalizedSub];
	if (!handler) {
		ctx.ui.notify(`Unknown subcommand: ${sub}`, "error");
		return;
	}
	await handler();
}

